var parecer = $('AI Agent').first().json.output || '';
var mapaRaw = $('Formatar Contexto').first().json.mapa_aliases || '{}';
var mapa = JSON.parse(mapaRaw);

Object.keys(mapa).forEach(function(alias) {
  parecer = parecer.split(alias).join(mapa[alias]);
});

return [{ json: { output: parecer } }];
